你的团队有一个用 C 写的图像处理库（基于 libvips），Go 服务需要调用它做缩略图生成。CTO 说「直接用 CGo 调用就行了」，但你隐约记得 Dave Cheney 说过「cgo is not Go」。

```go
// #cgo LDFLAGS: -lvips
// #include <vips/vips.h>
import "C"
import "unsafe"

func ResizeImage(data []byte, width, height int) ([]byte, error) {
    cData := C.CBytes(data) // Go → C 内存复制
    defer C.free(cData)

    var out *C.void
    var outLen C.size_t
    ret := C.vips_thumbnail_buffer(
        (*C.void)(cData), C.size_t(len(data)),
        &out, &outLen,
        C.int(width), C.int(height), nil)

    if ret != 0 {
        return nil, fmt.Errorf("vips error: %s", C.GoString(C.vips_error_buffer()))
    }
    defer C.free(unsafe.Pointer(out))
    return C.GoBytes(unsafe.Pointer(out), C.int(outLen)), nil
}
```

CGo 调用的真实开销是什么？为什么它不是「免费的 FFI」？在什么场景下应该避免 CGo？有哪些替代方案？
